class DropTargetImpl{spec;monitor;constructor(t,o){this.spec=t,this.monitor=o}canDrop(){const t=this.spec,o=this.monitor;return!t.canDrop||t.canDrop(o.getItem(),o)}hover(){const t=this.spec,o=this.monitor;t.hover&&t.hover(o.getItem(),o)}drop(){const t=this.spec,o=this.monitor;if(t.drop)return t.drop(o.getItem(),o)}}export{DropTargetImpl};